@namespace Lumeo
@implements IDisposable

@{
    var focusedItemId = _focusedIndex >= 0 && _focusedIndex < _items.Count ? _items[_focusedIndex].Id : null;
    var focusedItemValue = _focusedIndex >= 0 && _focusedIndex < _items.Count ? _items[_focusedIndex].Value : null;
    var context = new ComboboxContext(Value, Values, SearchText, Open, Multiple, IsSearchLoading, Creatable,
        EventCallback.Factory.Create<string>(this, OnValueSelected),
        EventCallback.Factory.Create<bool>(this, SetOpen),
        EventCallback.Factory.Create<string>(this, OnSearchChanged),
        EventCallback.Factory.Create<string>(this, OnCreateItem),
        _wrapperId, _contentId, _focusedIndex, focusedItemId, focusedItemValue,
        EventCallback.Factory.Create<int>(this, SetFocusedIndex),
        RegisterItem, UnregisterItem, _items.Count, EffectiveInvalid, Required,
        Items, ItemValue, ItemText, ItemGroup, ItemDisabled, ItemTemplate, Virtualize, ItemSize);
}

@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ml-0.5">*</span>
        }
    </label>
}

<CascadingValue Value="context" IsFixed="false">
    <div id="@_wrapperId" class="relative" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && !string.IsNullOrEmpty(ErrorText))
    {
        <p class="mt-1 text-xs text-destructive">@ErrorText</p>
    }
    else if (!string.IsNullOrEmpty(HelperText))
    {
        <p class="mt-1 text-xs text-muted-foreground">@HelperText</p>
    }
}

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string> ValueChanged { get; set; }
    /// <summary>
    /// Popover open state. Bind via <c>@bind-Open</c> when the Combobox lives inside
    /// a parent that re-renders heavily (e.g. an <c>EditForm</c> with active
    /// validation) — otherwise a parameter cascade can close the popover mid-click.
    /// In the bound (controlled) mode the parent owns state and the popover survives
    /// re-renders. When unbound, the component still functions but is vulnerable to
    /// the cascade-close race; binding is the recommended pattern.
    /// </summary>
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Multi-select
    [Parameter] public bool Multiple { get; set; }
    [Parameter] public HashSet<string>? Values { get; set; }
    [Parameter] public EventCallback<HashSet<string>> ValuesChanged { get; set; }

    // Creatable
    [Parameter] public bool Creatable { get; set; }
    [Parameter] public EventCallback<string> OnCreate { get; set; }

    // Async search
    [Parameter] public EventCallback<string> OnSearchAsync { get; set; }
    [Parameter] public int DebounceMs { get; set; } = 300;
    [Parameter] public bool IsSearchLoading { get; set; }

    // Validation
    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }

    // --- Data-bound mode (non-generic, purely additive) ---
    /// <summary>Optional data source. When set, <see cref="ComboboxContent"/> renders options from this list instead of ChildContent.</summary>
    [Parameter] public IEnumerable<object>? Items { get; set; }
    /// <summary>Extracts the string value for each item. Defaults to <c>ToString()</c>.</summary>
    [Parameter] public Func<object, string> ItemValue { get; set; } = it => it?.ToString() ?? "";
    /// <summary>Extracts the display label for each item. Defaults to <see cref="ItemValue"/> when null.</summary>
    [Parameter] public Func<object, string>? ItemText { get; set; }
    /// <summary>Optional group key extractor. When set, options are grouped under sticky headers.</summary>
    [Parameter] public Func<object, string?>? ItemGroup { get; set; }
    /// <summary>Optional per-item disabled predicate.</summary>
    [Parameter] public Func<object, bool>? ItemDisabled { get; set; }
    /// <summary>Optional custom render fragment for an item's content. Receives the raw item object.</summary>
    [Parameter] public RenderFragment<object>? ItemTemplate { get; set; }
    /// <summary>When <c>true</c> and <see cref="Items"/> is set, uses Blazor's Virtualize component for the option list.</summary>
    [Parameter] public bool Virtualize { get; set; }
    /// <summary>Estimated pixel height of each option row used by the Virtualize component. Default 36.</summary>
    [Parameter] public float ItemSize { get; set; } = 36f;

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    private readonly string _wrapperId = LumeoIds.New("combobox");
    private readonly string _contentId = LumeoIds.New("combobox-content");
    private string SearchText { get; set; } = "";
    private readonly DelayedDispatch _dispatch = new();
    private int _focusedIndex = -1;
    private readonly List<(string Id, string Value)> _items = new();

    private void RegisterItem(string id, string value)
    {
        if (!_items.Any(i => i.Id == id))
            _items.Add((id, value));
    }

    private void UnregisterItem(string id)
    {
        _items.RemoveAll(i => i.Id == id);
    }

    private async Task SetFocusedIndex(int index)
    {
        var count = _items.Count;
        if (count == 0) return;
        if (index < 0) index = 0;
        if (index >= count) index = count - 1;
        _focusedIndex = index;
        StateHasChanged();
        await Task.CompletedTask;
    }

    private async Task OnValueSelected(string value)
    {
        if (Multiple)
        {
            Values ??= [];
            if (Values.Contains(value))
                Values.Remove(value);
            else
                Values.Add(value);
            await ValuesChanged.InvokeAsync(Values);
        }
        else
        {
            Value = value;
            await ValueChanged.InvokeAsync(value);
            await SetOpen(false);
        }
    }

    private async Task SetOpen(bool value)
    {
        Open = value;
        if (!value && !Multiple)
        {
            SearchText = "";
            _focusedIndex = -1;
            _items.Clear();
        }
        await OpenChanged.InvokeAsync(value);
    }

    private async Task OnSearchChanged(string text)
    {
        SearchText = text;
        _focusedIndex = -1;

        // Only clear registered items for async search — async replaces the item set, so the old registrations
        // are stale. For static items (filtered by the parent's bound text), the items remain mounted and handle
        // their own register/unregister lifecycle; clearing here mis-reports ItemCount as 0 and triggers the
        // "no results" empty state while items are still visible.
        if (OnSearchAsync.HasDelegate)
        {
            _items.Clear();
            _dispatch.Schedule(DebounceMs, () => InvokeAsync(async () =>
            {
                await OnSearchAsync.InvokeAsync(text);
                StateHasChanged();
            }));
        }

        await Task.CompletedTask;
    }

    private async Task OnCreateItem(string value)
    {
        await OnCreate.InvokeAsync(value);
        if (Multiple)
        {
            Values ??= [];
            Values.Add(value);
            await ValuesChanged.InvokeAsync(Values);
        }
        else
        {
            Value = value;
            await ValueChanged.InvokeAsync(value);
            await SetOpen(false);
        }
        SearchText = "";
    }

    public void Dispose() => _dispatch.Dispose();

    public record ComboboxContext(
        string? Value, HashSet<string>? Values, string SearchText, bool IsOpen, bool Multiple, bool IsSearchLoading, bool Creatable,
        EventCallback<string> OnSelect, EventCallback<bool> SetOpen, EventCallback<string> OnSearch,
        EventCallback<string> OnCreateItem,
        string WrapperId, string ContentId, int FocusedIndex, string? FocusedItemId, string? FocusedItemValue,
        EventCallback<int> SetFocusedIndex,
        Action<string, string> RegisterItem, Action<string> UnregisterItem, int ItemCount,
        bool Invalid, bool Required,
        // Data-bound mode params (null when composition mode)
        IEnumerable<object>? Items,
        Func<object, string> ItemValue,
        Func<object, string>? ItemText,
        Func<object, string?>? ItemGroup,
        Func<object, bool>? ItemDisabled,
        RenderFragment<object>? ItemTemplate,
        bool Virtualize,
        float ItemSize);
}

@namespace Lumeo
@implements IAsyncDisposable
@using Microsoft.AspNetCore.Components.Web.Virtualization

@if (Context.IsOpen)
{
    <div id="@Context.ContentId" role="listbox" class="@CssClass"
         @onkeydown="HandleKeyDown" tabindex="-1" @attributes="AdditionalAttributes">
        @if (Context.IsSearchLoading)
        {
            <div class="flex items-center justify-center py-2 px-2 text-sm text-muted-foreground">
                <Spinner Class="h-4 w-4 mr-2" />
                @L["Combobox.Loading"]
            </div>
        }
        @if (Context.Items is not null)
        {
            @* Data-bound mode *@
            var filteredItems = FilteredItems;
            @if (Context.Virtualize)
            {
                <Virtualize Items="@filteredItems" Context="item" ItemSize="@Context.ItemSize">
                    @RenderBoundItem(item)
                </Virtualize>
            }
            else if (Context.ItemGroup is not null)
            {
                @foreach (var group in filteredItems.GroupBy(i => Context.ItemGroup(i) ?? ""))
                {
                    <div role="group">
                        @if (!string.IsNullOrEmpty(group.Key))
                        {
                            <div class="px-2 py-1.5 text-sm font-semibold">@group.Key</div>
                        }
                        @foreach (var item in group)
                        {
                            @RenderBoundItem(item)
                        }
                    </div>
                }
            }
            else
            {
                @foreach (var item in filteredItems)
                {
                    @RenderBoundItem(item)
                }
            }

            @if (filteredItems.Count == 0 && !Context.IsSearchLoading)
            {
                <div class="py-6 text-center text-sm text-muted-foreground">
                    @(EmptyText ?? L["Combobox.NoResults"])
                </div>
            }

            @if (Context.Creatable && !string.IsNullOrWhiteSpace(Context.SearchText) && filteredItems.Count == 0)
            {
                <button type="button" class="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 px-2 text-sm outline-none hover:bg-accent hover:text-accent-foreground border-t border-border/40 mt-1 pt-2"
                        @onclick="HandleCreate">
                    <Blazicon Svg="Lucide.Plus" class="h-3.5 w-3.5" />
                    <span>@string.Format(L["Combobox.Create"], Context.SearchText)</span>
                </button>
            }
        }
        else
        {
            @* Composition mode *@
            @ChildContent
            @if (!Context.IsSearchLoading && Context.ItemCount == 0 && ChildContent is null)
            {
                @* Fallback default empty — only renders if the consumer didn't supply any children at all.
                   The real empty state is `<ComboboxEmpty>` which renders itself when ItemCount hits 0. *@
                <div class="py-6 text-center text-sm text-muted-foreground">
                    @(EmptyText ?? L["Combobox.NoResults"])
                </div>
            }
            @if (Context.Creatable && !string.IsNullOrWhiteSpace(Context.SearchText) && Context.ItemCount == 0)
            {
                <button type="button" class="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 px-2 text-sm outline-none hover:bg-accent hover:text-accent-foreground border-t border-border/40 mt-1 pt-2"
                        @onclick="HandleCreate">
                    <Blazicon Svg="Lucide.Plus" class="h-3.5 w-3.5" />
                    <span>@string.Format(L["Combobox.Create"], Context.SearchText)</span>
                </button>
            }
        }
    </div>
}

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] public Combobox.ComboboxContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? EmptyText { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _registered;

    private string CssClass => $"fixed z-50 overflow-hidden rounded-md border border-border/60 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in {Class}".Trim();

    // Items filtered by the current search text (data-bound mode only).
    //
    // Previously a computed property: at 10k items it ran the Where+ToList for
    // every access, and the markup above accesses it 3+ times per render
    // (Virtualize Items, foreach, Count checks). Now we memoize: recompute
    // only when the Items reference changes OR the search text changes.
    // Invalidation happens in OnParametersSet — any external state mutation
    // that flows through a parameter pass (which is the only way Combobox
    // updates its descendants) gets picked up.
    // Keep the concrete type List<object> — the markup uses .Count and passes
    // this list to <Virtualize Items=...> which wants an ICollection<T>.
    private List<object> _filteredItems = new();
    private IEnumerable<object>? _lastItems;
    private string? _lastSearchText;

    private List<object> FilteredItems => _filteredItems;

    protected override void OnParametersSet()
    {
        var items = Context?.Items;
        var search = Context?.SearchText;

        if (!ReferenceEquals(items, _lastItems) || !string.Equals(search, _lastSearchText, StringComparison.Ordinal))
        {
            _lastItems = items;
            _lastSearchText = search;
            _filteredItems = ComputeFiltered(items, search);
        }
    }

    private List<object> ComputeFiltered(IEnumerable<object>? items, string? searchText)
    {
        if (items is null) return new();
        if (string.IsNullOrEmpty(searchText))
            return items.ToList();

        return items.Where(item =>
        {
            var text = Context.ItemText?.Invoke(item) ?? Context.ItemValue(item);
            return text.Contains(searchText, StringComparison.OrdinalIgnoreCase);
        }).ToList();
    }

    private RenderFragment RenderBoundItem(object item) => builder =>
    {
        var value = Context.ItemValue(item);
        var isSelected = Context.Multiple
            ? Context.Values?.Contains(value) == true
            : Context.Value == value;
        var isDisabled = Context.ItemDisabled?.Invoke(item) ?? false;
        var itemId = $"combobox-item-bound-{value.GetHashCode():X}";
        var isFocused = Context.FocusedItemId == itemId;

        builder.OpenElement(0, "button");
        builder.AddAttribute(1, "type", "button");
        builder.AddAttribute(2, "id", itemId);
        builder.AddAttribute(3, "role", "option");
        builder.AddAttribute(4, "aria-selected", isSelected.ToString().ToLower());
        var cssClass = Cx.Join(
            "relative flex w-full cursor-pointer select-none items-center gap-2 rounded-sm py-1.5 pl-2 pr-8 text-sm outline-none hover:bg-accent hover:text-accent-foreground",
            Cx.When(isFocused, "bg-accent text-accent-foreground"));
        builder.AddAttribute(5, "class", cssClass);
        if (!isDisabled)
        {
            builder.AddAttribute(6, "onclick", EventCallback.Factory.Create(this, () => Context.OnSelect.InvokeAsync(value)));
        }
        builder.OpenElement(7, "span");
        builder.AddAttribute(8, "class", "flex h-3.5 w-3.5 items-center justify-center");
        if (isSelected)
        {
            builder.OpenComponent<Blazicons.Blazicon>(9);
            builder.AddAttribute(10, "Svg", Blazicons.Lucide.Check);
            builder.AddAttribute(11, "class", "h-3.5 w-3.5");
            builder.CloseComponent();
        }
        builder.CloseElement(); // span

        if (Context.ItemTemplate is not null)
        {
            builder.AddContent(12, Context.ItemTemplate(item));
        }
        else
        {
            var label = Context.ItemText?.Invoke(item) ?? value;
            builder.AddContent(12, label);
        }
        builder.CloseElement(); // button
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen && !_registered)
        {
            await Interop.PositionFixed(Context.ContentId, Context.WrapperId, "start", true);
            await Interop.RegisterClickOutside(Context.ContentId, null, async () =>
            {
                await Context.SetOpen.InvokeAsync(false);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;
        }
        else if (!Context.IsOpen && _registered)
        {
            await Cleanup();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await Context.SetOpen.InvokeAsync(false);
                break;
            case "ArrowDown":
                await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex + 1);
                break;
            case "ArrowUp":
                await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex > 0 ? Context.FocusedIndex - 1 : 0);
                break;
            case "Home":
                await Context.SetFocusedIndex.InvokeAsync(0);
                break;
            case "End":
                await Context.SetFocusedIndex.InvokeAsync(int.MaxValue);
                break;
            case "Enter":
                if (Context.FocusedItemValue is not null)
                    await Context.OnSelect.InvokeAsync(Context.FocusedItemValue);
                break;
        }
    }

    private async Task HandleCreate()
    {
        await Context.OnCreateItem.InvokeAsync(Context.SearchText);
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(Context.ContentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(Context.ContentId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@if (!string.IsNullOrWhiteSpace(Context.SearchText) && ShowCreate)
{
    <button type="button" class="@CssClass" @onclick="HandleCreate" @attributes="AdditionalAttributes">
        <Blazicon Svg="Lucide.Plus" class="h-3.5 w-3.5 mr-2" />
        @string.Format(L["Combobox.Create"], Context.SearchText)
    </button>
}

@code {
    [CascadingParameter] public Combobox.ComboboxContext Context { get; set; } = default!;
    [Parameter] public EventCallback<string> OnCreate { get; set; }
    [Parameter] public bool ShowCreate { get; set; } = true;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 px-2 text-sm outline-none hover:bg-accent hover:text-accent-foreground border-t border-border/40 mt-1 pt-2 {Class}".Trim();

    private async Task HandleCreate()
    {
        await OnCreate.InvokeAsync(Context.SearchText);
    }
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@* Only renders when the parent Combobox reports zero registered items — previously it rendered unconditionally
   so users saw the empty state stacked under their visible items. *@
@if (IsVisible)
{
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @if (ChildContent is not null)
        {
            @ChildContent
        }
        else
        {
            <span>@L["Combobox.NoResults"]</span>
        }
    </div>
}

@code {
    [CascadingParameter] public Combobox.ComboboxContext? Context { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsVisible => Context is null || (!Context.IsSearchLoading && Context.ItemCount == 0);

    private string CssClass => $"py-6 text-center text-sm text-muted-foreground {Class}".Trim();
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<div class="relative">
    <Blazicon Svg="Lucide.Search" class="absolute start-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
    <input type="text"
           role="combobox"
           aria-haspopup="listbox"
           aria-expanded="@Context.IsOpen.ToString().ToLower()"
           aria-controls="@Context.ContentId"
           aria-autocomplete="list"
           aria-activedescendant="@(Context.IsOpen ? Context.FocusedItemId : null)"
           class="@CssClass"
           placeholder="@(Placeholder ?? L["Combobox.SearchPlaceholder"])"
           value="@Context.SearchText"
           @oninput="HandleInput"
           @onfocus="Open"
           @onkeydown="HandleKeyDown"
           @attributes="AdditionalAttributes" />
</div>

@code {
    [CascadingParameter] public Combobox.ComboboxContext Context { get; set; } = default!;
    [Parameter] public string? Placeholder { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"flex h-9 w-full rounded-md border {(Context.Invalid ? "border-destructive" : "border-input")} bg-transparent py-2 ps-8 pe-3 text-sm placeholder:text-muted-foreground focus-visible:outline-none {(Context.Invalid ? "focus-visible:ring-[1.5px] focus-visible:ring-destructive/20" : "")} {Class}".Trim();

    private async Task HandleInput(ChangeEventArgs e)
    {
        var text = e.Value?.ToString() ?? "";
        await Context.OnSearch.InvokeAsync(text);
        if (!Context.IsOpen)
        {
            await Context.SetOpen.InvokeAsync(true);
        }
    }

    private async Task Open()
    {
        if (!Context.IsOpen)
        {
            await Context.SetOpen.InvokeAsync(true);
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowDown":
                if (!Context.IsOpen)
                    await Context.SetOpen.InvokeAsync(true);
                else
                    await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex + 1);
                break;
            case "ArrowUp":
                if (Context.IsOpen)
                    await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex > 0 ? Context.FocusedIndex - 1 : 0);
                break;
            case "Home":
                if (Context.IsOpen)
                    await Context.SetFocusedIndex.InvokeAsync(0);
                break;
            case "End":
                if (Context.IsOpen)
                    await Context.SetFocusedIndex.InvokeAsync(int.MaxValue);
                break;
            case "Enter":
                if (Context.IsOpen && Context.FocusedItemValue is not null)
                    await Context.OnSelect.InvokeAsync(Context.FocusedItemValue);
                break;
            case "Escape":
                await Context.SetOpen.InvokeAsync(false);
                break;
        }
    }
}

@namespace Lumeo
@implements IDisposable

@if (Visible)
{
    <button type="button" id="@_itemId" role="option" aria-selected="@IsSelected.ToString().ToLower()"
            class="@CssClass" @onclick="Select" @attributes="AdditionalAttributes">
        <span class="flex h-3.5 w-3.5 items-center justify-center">
            @if (IsSelected)
            {
                <Blazicon Svg="Lucide.Check" class="h-3.5 w-3.5" />
            }
        </span>
        @ChildContent
    </button>
}

@code {
    [CascadingParameter] public Combobox.ComboboxContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public string? Class { get; set; }
    /// <summary>Optional text used to match against the search input. Falls back to Value.</summary>
    [Parameter] public string? SearchValue { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = LumeoIds.New("combobox-item");
    private bool _registered;

    private bool IsSelected => Context.Multiple
        ? Context.Values?.Contains(Value) == true
        : Context.Value == Value;

    private bool IsFocused => Context.FocusedItemId == _itemId;

    private bool Visible
    {
        get
        {
            if (string.IsNullOrEmpty(Context.SearchText)) return true;
            var haystack = SearchValue ?? Value;
            return haystack.Contains(Context.SearchText, StringComparison.OrdinalIgnoreCase);
        }
    }

    private string CssClass => Cx.Join(
        "relative flex w-full cursor-pointer select-none items-center gap-2 rounded-sm py-1.5 pl-2 pr-8 text-sm outline-none hover:bg-accent hover:text-accent-foreground",
        Cx.When(IsFocused, "bg-accent text-accent-foreground"),
        Class);

    protected override void OnParametersSet()
    {
        if (Visible && !_registered)
        {
            Context.RegisterItem(_itemId, Value);
            _registered = true;
        }
        else if (!Visible && _registered)
        {
            Context.UnregisterItem(_itemId);
            _registered = false;
        }
    }

    public void Dispose()
    {
        if (_registered) Context.UnregisterItem(_itemId);
    }

    private async Task Select() => await Context.OnSelect.InvokeAsync(Value);
}
